<?php
namespace Tests\Feature;use App\Domain\Media\CharacterVisuals\CharacterVisualAssetException;use App\Domain\Media\CharacterVisuals\CharacterVisualAssetService;use App\Models\CharacterClass;use App\Models\CharacterTemplate;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class CharacterVisualTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();Storage::fake('public');}private function template($status='inactive'){return CharacterTemplate::factory()->create(['character_class_id'=>CharacterClass::where('code','adventurer')->firstOrFail()->id,'status'=>$status]);}
public function test_png_generates_three_aligned_variants_and_metadata(){$t=$this->template();$file=UploadedFile::fake()->image('body.png',512,768);$asset=app(CharacterVisualAssetService::class)->replace($t,$file);$this->assertSame('character_template',$asset->mediable_type);$this->assertSame('base_visual',$asset->asset_type);$this->assertSame(256,$asset->width);$this->assertSame('2:3',$asset->metadata['canvas']['ratio']);foreach([128,256,512]as$s)Storage::disk('public')->assertExists($asset->metadata['variants'][(string)$s]);$this->assertTrue(app(CharacterVisualAssetService::class)->isActivationReady($t->fresh()));}
public function test_wrong_ratio_is_rejected_without_orphans(){$t=$this->template();$this->expectException(CharacterVisualAssetException::class);app(CharacterVisualAssetService::class)->replace($t,UploadedFile::fake()->image('square.png',512,512));}
public function test_active_image_cannot_be_removed_but_inactive_can(){$t=$this->template();app(CharacterVisualAssetService::class)->replace($t,UploadedFile::fake()->image('body.png',512,768));$t->update(['status'=>'active']);try{app(CharacterVisualAssetService::class)->delete($t->fresh());$this->fail();}catch(CharacterVisualAssetException $e){$this->assertSame('Inactiva la plantilla antes de eliminar su imagen base.',$e->getMessage());}$t->update(['status'=>'inactive']);app(CharacterVisualAssetService::class)->delete($t->fresh());$this->assertFalse($t->mediaAssets()->exists());$this->assertFalse(app(CharacterVisualAssetService::class)->presentation($t->fresh())->exists());}
}
